import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../api/axiosConfig';
import toast from 'react-hot-toast';
import { UserPlus, Mail, Lock, ShieldAlert, Cpu, Activity } from 'lucide-react';

const RegisterPage = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    
    // Security check for key parity
    if (formData.password !== formData.confirmPassword) {
      return toast.error("SECURITY_MISMATCH: Passwords do not match.");
    }

    const toastId = toast.loading("INITIALIZING_NEW_NODE...");
    setLoading(true);

    try {
      // Direct call to FastAPI registration endpoint
      await api.post('/auth/register', {
        email: formData.email,
        password: formData.password
      });
      
      toast.success("IDENTITY_CREATED: Please log in.", { id: toastId });
      navigate('/login');
    } catch (err) {
      const errorMsg = err.response?.data?.detail || "REGISTRATION_FAILED";
      toast.error(`GATE_REJECTION: ${errorMsg.toUpperCase()}`, { id: toastId });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center p-4 reveal-data">
      <div className="w-full max-w-md terminal-card relative">
        
        {/* Header: Node Identity Setup */}
        <div className="text-center mb-10">
          <div className="inline-block p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 mb-4 text-emerald-500">
            <UserPlus size={32} />
          </div>
          <h2 className="text-2xl font-bold tracking-[0.4em] text-white uppercase">Initialize_Node</h2>
          <p className="text-[9px] text-white/20 mt-2 uppercase tracking-widest font-mono">
            Identity Setup // System_V3.0_Core
          </p>
        </div>

        {/* Node Initialization Progress Bar (Visual Only) */}
        <div className="mb-8 px-2">
          <div className="flex justify-between text-[8px] text-emerald-500/50 uppercase mb-2 tracking-widest">
            <span>Security_Check</span>
            <span>{loading ? '65%' : '0%'}</span>
          </div>
          <div className="h-1 bg-white/5 rounded-full overflow-hidden">
            <div 
              className={`h-full bg-emerald-500 transition-all duration-1000 ${loading ? 'w-[65%]' : 'w-0'}`}
            />
          </div>
        </div>

        <form onSubmit={handleRegister} className="space-y-5">
          {/* Email Input */}
          <div className="space-y-2">
            <label className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-2 mb-1">
              <Mail size={12} /> Registry_Email
            </label>
            <input 
              type="email"
              className="terminal-input"
              placeholder="operator@node.ai"
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required
            />
          </div>

          {/* Password Input */}
          <div className="space-y-2">
            <label className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-2 mb-1">
              <Lock size={12} /> Master_Key
            </label>
            <input 
              type="password"
              className="terminal-input"
              placeholder="••••••••"
              onChange={(e) => setFormData({...formData, password: e.target.value})}
              required
            />
          </div>

          {/* Confirm Password Input */}
          <div className="space-y-2">
            <label className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-2 mb-1">
              <ShieldAlert size={12} /> Confirm_Key
            </label>
            <input 
              type="password"
              className="terminal-input"
              placeholder="••••••••"
              onChange={(e) => setFormData({...formData, confirmPassword: e.target.value})}
              required
            />
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full emerald-btn py-4 mt-6 group"
          >
            {loading ? (
              <Activity size={16} className="animate-spin" />
            ) : (
              <span className="flex items-center gap-2">
                <Cpu size={16} /> Create_Identity_Node
              </span>
            )}
          </button>
        </form>

        {/* Existing Node Link */}
        <div className="mt-8 pt-6 border-t border-white/5 text-center">
          <p className="text-[10px] text-white/30 uppercase tracking-widest">
            Identity exists? 
            <Link to="/login" className="ml-2 text-emerald-500 underline hover:text-emerald-400 transition-colors">
              Access_Gate
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
